  p_clinic_id: $('Get Empresa').first().json.id,
  p_telefone: $('Edit Fields1').first().json.numCliente,
  p_resumo: String($('Edit Fields1').first().json.msg ?? '')
}) }}

parameters.jsCode:
const item = { ...$input.first().json };
// NOTA: Set node v3.4 dropa o body original, usar campos do Edit Fields1 diretamente
function digits(s) {
  return String(s ?? '').replace(/[^0-9]/g, '');
}
// Evento vem de item.event (setado pelo Edit Fields1 de body.event)
const rawEvent = item.event || '';
let event = String(rawEvent).trim().split('.').join('_').split('-').join('_').toUpperCase();
if (!event && item.numCliente) event = 'MESSAGES_UPSERT';

// instance_name vem de item.instanceName (setado pelo Edit Fields1 de body.instance)
const instance_name = String(item.instanceName || item.instanceId || '').trim();

// numero_clinica vem de item.numEmpresa (setado pelo Edit Fields1 de body.sender), so digitos
const numero_clinica = digits(item.numeroClinica || item.numEmpresa || '');

const whSrc = item._wh_source === 'test' ? 'test' : 'prod';
const _tenant = { event, instance_name, numero_clinica, wh_source: whSrc };
return [{ json: { ...item, _tenant } }];

const base = $('Code Normalizar Evolution Clinica').first().json;
const raw = $input.first().json;
const row = Array.isArray(raw) ? (raw[0] ?? {}) : raw;
const cenario =
  row.cenario ||
  (raw && typeof raw === 'object' && !Array.isArray(raw) && raw.message ? 'clinica_nao_encontrada' : null) ||
  'clinica_nao_encontrada';
return [{ json: { ...base, ...row, cenario } }];

return items.map(item => {
  const texto = item.json.answer || '';
  const match = texto.match(/https?:\/\/[^\s]+?\.(jpg|jpeg|png|gif)(\?[^\s]*)?/i);

  return {
    json: {
      imagem: match ? match[0] : null
    }
  };
});

const row = ($input.first().json[0] || $input.first().json);
const rawInstr = row?.agent_instructions;
const clinic_name = row?.name || '';

let agent_instructions = '';
let nome_agente = '';

if (rawInstr) {
  try {
    const cfg = typeof rawInstr === 'string' ? JSON.parse(rawInstr) : rawInstr;
    nome_agente = cfg.nome_agente || '';
    const secoes = [
      { key: 'identidade', label: 'IDENTIDADE DO AGENTE' },
      { key: 'triagem',    label: 'TRIAGEM E URGENCIAS' },
      { key: 'tom',        label: 'TOM E LINGUAGEM' },
      { key: 'orientacoes',label: 'ORIENTACOES AO PACIENTE' },
      { key: 'transferir', label: 'QUANDO TRANSFERIR PARA HUMANO' },
      { key: 'outros',     label: 'OUTRAS INSTRUCOES' },
    ];
    agent_instructions = secoes
      .filter(s => typeof cfg[s.key] === 'string' && cfg[s.key].trim())
      .map(s => '### ' + s.label + '\n' + cfg[s.key].trim())
      .join('\n\n');
  } catch(e) { agent_instructions = String(rawInstr); }
}

const mensagem = $('Edit Fields2').first().json.mensagem;
return [{ json: { mensagem, agent_instructions, nome_agente, clinic_name } }];

